INSERT OR IGNORE INTO spell(id, eid, key, name, description, spell_type, mana_cost, game_id, version, created_by_sub, created_at, updated_at, deleted_at)
VALUES
  (1, 'e1000000-0000-0000-0000-000000000001', 'wh3_main_spell_nurgle_curse_of_the_leper', 'Curse of the Leper', 'As the caster speaks, his followers are blessed with resilience, whilst his enemies watch in horror as their limbs wither and drop off.', 'wh_type_augment', 7, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (2, 'e1000000-0000-0000-0000-000000000002', 'wh3_main_spell_nurgle_fleshy_abundance', 'Fleshy Abundance', 'The most repulsive growth spurt imaginable occurs – the wobbling mounds of fat sealing wounds as soon as they are formed.', 'wh_type_regeneration', 16, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (3, 'e1000000-0000-0000-0000-000000000003', 'wh3_main_spell_nurgle_miasma_of_pestilence', 'Miasma of Pestilence', 'The most putrescent vapour fills the air, loosening lunches and bowels, and causing violent, crippling vomiting seizures in nearby foes.', 'wh_type_hex', 4, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (4, 'e1000000-0000-0000-0000-000000000004', 'wh3_main_spell_nurgle_pestilent_pustule', 'Blight Boil', 'This filthy, pulsating blister rapidly grows before suddenly bursting, showering the enemy with its disgusting fluid and all the maladies contained within.', 'wh_type_explosion', 13, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (5, 'e1000000-0000-0000-0000-000000000005', 'wh3_main_spell_nurgle_rancid_visitations', 'Rancid Visitations', 'The enemy is gifted the Plague Lord''s nightmarish necrosis, causing their skin to blacken and their internal organs to mulch.', 'wh_type_direct_damage', 15, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (6, 'e1000000-0000-0000-0000-000000000006', 'wh3_main_spell_nurgle_stream_of_corruption', 'Stream of Corruption', 'A poisonous spurt of diseased gas and bile spews forth from the spellcaster''s diseased lungs, drenching the enemy in vile, choking pus.', 'wh_type_breath', 5, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (7, 'e1000000-0000-0000-0000-000000000007', 'wh3_main_spell_slaanesh_acquiescence', 'Acquiescence', 'The spellcaster''s corrupting touch puts their victims into a blissful, euphoric state for a short time, rendering them little able to move, let alone defend themselves.', 'wh_type_hex', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (8, 'e1000000-0000-0000-0000-000000000008', 'wh3_main_spell_slaanesh_hysterical_frenzy', 'Hysterical Frenzy', 'The caster''s victims are engulfed by a torrent of unreasoning emotion, excruciating pain and blissful rapture, causing them to embark on a riotous, clawing rampage.', 'wh_type_augment', 8, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (9, 'e1000000-0000-0000-0000-000000000009', 'wh3_main_spell_slaanesh_lash_of_slaanesh', 'Lash of Slaanesh', 'The exquisite kiss of the Dark Prince''s three-tailed whip strikes the enemy with a delicious fury.', 'wh_type_breath', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (10, 'e1000000-0000-0000-0000-00000000000a', 'wh3_main_spell_slaanesh_pavane_of_slaanesh', 'Pavane of Slaanesh', 'Whistling one of Slaanesh’s perverse darkling dances causes the foe''s bones to jerk spasmodically until they break.', 'wh_type_direct_damage', 14, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (11, 'e1000000-0000-0000-0000-00000000000b', 'wh3_main_spell_slaanesh_phantasmagoria', 'Phantasmagoria', 'A complex sigil is performed, transfixing the enemy with a shifting array of hallucinatory images that disjoint and befuddle, inviting their deaths.', 'wh_type_area_of_hexes', 15, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (12, 'e1000000-0000-0000-0000-00000000000c', 'wh3_main_spell_slaanesh_slicing_shards', 'Slicing Shards', 'A mirror forms in the sky only to be shattered into a myriad of deadly shards that lacerate the enemy below.', 'wh_type_bombardment', 12, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (13, 'e1000000-0000-0000-0000-00000000000d', 'wh3_main_spell_tzeentch_blue_fire_of_tzeentch', 'Blue Fire of Tzeentch', 'With a twist of the hand, the spellcaster causes the bodies of their opponents to be consumed by coruscating blue flames.', 'wh_type_magic_missiles', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (14, 'e1000000-0000-0000-0000-00000000000e', 'wh3_main_spell_tzeentch_glean_magic', 'Glean Magic', 'Reaching into his enemy''s mind, the spellcaster steals their sorcery for his own diabolical use.', 'wh_type_hex_of_the_winds', 9, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (15, 'e1000000-0000-0000-0000-00000000000f', 'wh3_main_spell_tzeentch_infernal_gateway', 'Infernal Gateway', 'A portal to the Realm of Chaos opens; a magical tear in the mortal plane that sucks those nearby inside to face certain madness, if not their doom.', 'wh_type_vortex', 18, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (16, 'e1000000-0000-0000-0000-000000000010', 'wh3_main_spell_tzeentch_pink_fire_of_tzeentch', 'Pink Fire of Tzeentch', 'A roiling tide of iridescent energy flows from the spellcaster, enveloping their enemies in a cone of searing magical flame.', 'wh_type_breath', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (17, 'e1000000-0000-0000-0000-000000000011', 'wh3_main_spell_tzeentch_treason_of_tzeentch', 'Treason of Tzeentch', 'The spellcaster whispers into the enemies'' minds, subtly stoking the fires of mistrust and treachery.', 'wh_type_area_of_hexes', 8, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (18, 'e1000000-0000-0000-0000-000000000012', 'wh3_main_spell_tzeentch_tzeentchs_firestorm', 'Tzeentch''s Firestorm', 'Blistering balls of scarlet flame emanate from the spellcaster to engulf the foe in deadly balefire.', 'wh_type_vortex', 15, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (19, 'e1000000-0000-0000-0000-000000000013', 'wh_dlc05_spell_shadow_melkoths_mystifying_miasma', 'Melkoth''s Mystifying Miasma', 'The caster weaves a confounding fog that numbs and deludes enemies, causing them to stumble and stagger.', 'wh_type_direct_damage', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (20, 'e1000000-0000-0000-0000-000000000014', 'wh_dlc05_spell_shadow_okkams_mindrazor', 'Okkam''s Mindrazor', 'The supernatural solution is often the best; weapons materialise before the caster''s allies, allowing them to slice through flesh, soul, and consciousness.', 'wh_type_augment', 8, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (21, 'e1000000-0000-0000-0000-000000000015', 'wh_dlc05_spell_shadow_pit_of_shades', 'Pit of Shades', 'The spellcaster opens a vortex leading into the Pit. Anything caught within it will be lost forever.', 'wh_type_vortex', 15, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (22, 'e1000000-0000-0000-0000-000000000016', 'wh_dlc05_spell_shadow_the_enfeebling_foe', 'The Enfeebling Foe', 'When cast, this spell enfeebles enemy minds; they feel the crushing weight of reality bearing down upon them.', 'wh_type_hex', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (23, 'e1000000-0000-0000-0000-000000000017', 'wh_dlc05_spell_shadow_the_penumbral_pendulum', 'The Penumbral Pendulum', 'A spectral pendulum is summoned by the Wizard. On command, it swings, razor sharp and with lethal speed, through the foe.', 'wh_type_wind', 12, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (24, 'e1000000-0000-0000-0000-000000000018', 'wh_dlc05_spell_shadow_the_withering', 'The Withering', 'The Wizard destroys the foe from within, corroding their minds with doubt and crisis.', 'wh_type_hex', 5, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (25, 'e1000000-0000-0000-0000-000000000019', 'wh_main_spell_death_aspect_of_the_dreadknight', 'Aspect of the Dread Knight', 'An invisible aura of horror surrounds the Wizard’s allies. Only the bravest foes now stand before them.', 'wh_type_augment', 4, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (26, 'e1000000-0000-0000-0000-00000000001a', 'wh_main_spell_death_doom_and_darkness', 'Doom & Darkness', 'Spirits of the departed assail the Wizard’s foes, sapping their resolve and causing dread among their numbers.', 'wh_type_hex', 5, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (27, 'e1000000-0000-0000-0000-00000000001b', 'wh_main_spell_death_soulblight', 'Soulblight', 'Harnessing the sickly power of Shyish, the Wizard weakens the foe''s will to survive the battle.', 'wh_type_area_of_hexes', 7, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (28, 'e1000000-0000-0000-0000-00000000001c', 'wh_main_spell_death_spirit_leech', 'Spirit Leech', 'The Wizard extends an ebon hand towards the chosen foe, leeching its spirit through tainted sorcery.', 'wh_type_direct_damage', 8, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (29, 'e1000000-0000-0000-0000-00000000001d', 'wh_main_spell_death_the_fate_of_bjuna', 'The Fate of Bjuna', 'Following the fate of the unsmiling warrior, Bjuna, the targets of the caster’s ire will laugh themselves to death.', 'wh_type_direct_damage', 22, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (30, 'e1000000-0000-0000-0000-00000000001e', 'wh_main_spell_death_the_purple_sun_of_xereus', 'The Purple Sun of Xereus', 'A colossal orb of purple-edged darkness materialises - those who do not escape its crystalline touch are doomed for eternity!', 'wh_type_vortex', 18, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (31, 'e1000000-0000-0000-0000-00000000001f', 'wh_main_spell_fire_piercing_bolts_of_burning', 'Piercing Bolts of Burning', 'Focusing all his mystical might, the Pyromancer strikes the foe with a flurry of incandescent missiles.', 'wh_type_bombardment', 10, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (32, 'e1000000-0000-0000-0000-000000000020', 'wh_main_spell_fire_piercing_bolts_of_burning_upgraded', 'Piercing Bolts of Burning Upgraded', 'Focusing all his mystical might, the Pyromancer strikes the foe with a flurry of incandescent missiles.', 'wh_type_bombardment', 16, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (33, 'e1000000-0000-0000-0000-000000000021', 'wh_main_spell_fire_the_burning_head', 'The Burning Head', 'A cackling, flaming visage appears before the Wizard. With a gleeful screech, it swirls around the battlefield, immolating anything in its way.', 'wh_type_wind', 10, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (34, 'e1000000-0000-0000-0000-000000000022', 'wh_main_spell_fire_the_burning_head_upgraded', 'The Burning Head Upgraded', 'A cackling, flaming visage appears before the Wizard. With a gleeful screech, it swirls around the battlefield, immolating anything in its way.', 'wh_type_wind', 16, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (35, 'e1000000-0000-0000-0000-000000000023', 'wh_main_spell_metal_final_transmutation', 'Final Transmutation', 'The Wizard unleashes a hail of magical energy, transmuting his foes into Unliving golden statues.', 'wh_type_area_of_direct_damage', 17, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (36, 'e1000000-0000-0000-0000-000000000024', 'wh_main_spell_metal_gehennas_golden_hounds', 'Gehenna''s Golden Hounds', 'Blowing on a glimmering golden whistle, the Wizard summons the spirit of Gehenna’s metal hounds to hunt down his prey.', 'wh_type_vortex', 8, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (37, 'e1000000-0000-0000-0000-000000000025', 'wh_main_spell_metal_glittering_robe', 'Glittering Robe', 'The Alchemist conjures a gaudy cloak of shimmering scale to improve his allies’ defensive stance.', 'wh_type_augment', 5, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (38, 'e1000000-0000-0000-0000-000000000026', 'wh_main_spell_metal_plague_of_rust', 'Plague of Rust', 'The enemy target''s armour begins to rust, disappearing in clouds of tiny flakes and weakening his defensive abilities.', 'wh_type_hex', 4, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (39, 'e1000000-0000-0000-0000-000000000027', 'wh_main_spell_metal_searing_doom', 'Searing Doom', 'A spray of sizzling silver slivers rain from the sky to impale the caster''s enemy.', 'wh_type_bombardment', 6, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (40, 'e1000000-0000-0000-0000-000000000028', 'wh_main_spell_metal_transmutation_of_lead', 'Transmutation of Lead', 'The enemies’ weapons become heavy, cumbersome, and almost impossible to wield in battle.', 'wh_type_area_of_hexes', 11, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null);
